INSERT OR REPLACE INTO `audit_reports` (`id`, `ticker`, `year`, `report_type`, `auditor_name`, `audit_opinion`, `going_concern_issue`, `going_concern_detail`) VALUES
('VISECO_2017_consolidated', 'VISECO', 2017, 'consolidated', 'Công ty TNHH Kiểm toán và Tư vấn UHY', 'unqualified', 0, NULL),
('VISECO_2016_consolidated', 'VISECO', 2016, 'consolidated', 'Công ty TNHH Kiểm toán và Tư vấn UHY ACA', 'unqualified', 0, NULL),
('VIR_2024_consolidated', 'VIR', 2024, 'consolidated', 'Công ty TNHH Kiểm toán FAC - Chi nhánh Đệ Nhất', 'disclaimer', 1, 'Công ty bị cưỡng chế thu hồi đất, phá dỡ toàn bộ tài sản kinh doanh tại khu vực bãi tắm đường Thùy Vân, TP. Vũng Tàu; Ban Giám đốc chưa có kế hoạch phục hồi cụ thể; không thu thập đủ bằng chứng để đánh giá giả định hoạt động liên tục.'),
('VIR_2022_consolidated', 'VIR', 2022, 'consolidated', 'Công ty TNHH Kiểm toán FAC - Chi nhánh Đệ Nhất', 'disclaimer', 1, 'Kiểm toán viên không thể thu thập đủ bằng chứng kiểm toán do Công ty chưa được ký kết hợp đồng thuê đất, thuê cơ sở hạ tầng, và có tranh chấp, khiếu nại liên quan đến tiền thuê đất, cơ sở hạ tầng bị truy thu (tổng số tiền 38,469,784,319 VND), dẫn đến nghi ngờ về khả năng hoạt động liên tục.'),
('VIR_2025_consolidated', 'VIR', 2025, 'consolidated', 'Công ty TNHH Kiểm toán FAC - Chi nhánh Đệ Nhất', 'disclaimer', 1, 'Công ty bị thu hồi đất tại Vũng Tàu Intourco Resort, dẫn đến nghi ngờ đáng kể về khả năng hoạt động liên tục.'),
('VIR_2021_consolidated', 'VIR', 2021, 'consolidated', 'Công ty TNHH Kiểm toán FAC', 'disclaimer', 0, NULL),
('VIR_2020_consolidated', 'VIR', 2020, 'consolidated', 'Công ty TNHH Kiểm toán FAC - Chi nhánh Đệ Nhất', 'disclaimer', 0, NULL),
('VIR_2019_consolidated', 'VIR', 2019, 'consolidated', 'Công ty TNHH Kiểm toán FAC', 'disclaimer', 1, 'Thanh tra tỉnh ban hành Kết luận số 261/KL-TTr về việc thu hồi tiền thuê đất (34.490.774.319 VND) và tiền thuê hạ tầng kỹ thuật (3.979.010.000 VND) tại Bãi Thủy Vân. Công ty chưa được cơ quan có thẩm quyền ký hợp đồng cho thuê đất/hạ tầng, chưa thống nhất giá thuê, chi phí ghi nhận thiếu chưa xác định được. Công ty đang kiến nghị xem xét lại. Kiểm toán viên không thu thập đủ bằng chứng kiểm toán nên từ chối đưa ra ý kiến.'),
('VIR_2018_consolidated', 'VIR', 2018, 'consolidated', 'Công ty TNHH Kiểm toán FAC', 'disclaimer', 0, NULL),
