('VikkiBankS_2025_consolidated', 'VikkiBankS', 2025, 'consolidated', 'Công ty TNHH Ernst & Young Việt Nam', 'qualified', 0, NULL),
('VIM_2018_consolidated', 'VIM', 2018, 'consolidated', 'Công ty TNHH Hãng Kiểm toán AASC', 'unqualified', 0, NULL),
