('VIH_2023_consolidated', 'VIH', 2023, 'consolidated', 'Công ty TNHH Hăng Kiểm toán AASC', 'unqualified', 0, NULL),
('VIH_2020_consolidated', 'VIH', 2020, 'consolidated', 'Công ty TNHH Hãng Kiểm toán AASC', 'qualified', 0, NULL),
('VIH_2021_consolidated', 'VIH', 2021, 'consolidated', 'Công ty TNHH Hãng Kiểm toán AASC', 'unqualified', 0, NULL),
('VIH_2019_consolidated', 'VIH', 2019, 'consolidated', 'Công ty TNHH Hãng Kiểm toán AASC', 'unqualified', 1, 'Báo cáo tài chính vẫn được trình bày dựa trên cơ sở giả định hoạt động liên tục vì Công ty là Công ty con của Tổng Công ty Viglacera - CTCP nên vẫn duy trì được sự hỗ trợ về tài chính, nguồn lực, công nghệ; dây chuyền sản xuất gạch bán sứ hoạt động ổn định, sản phẩm đầu ra tiêu thụ tăng cao, kinh doanh tiếp tục có lãi và lợi nhuận lũy kế tăng dần; Công ty dự kiến đảm bảo cân đối đủ vốn lưu động phục vụ hoạt động kinh doanh.'),
('VIH_2017_consolidated', 'VIH', 2017, 'consolidated', 'Hãng Kiểm toán AASC', 'unqualified', 0, NULL),
('VIE_2025_consolidated', 'VIE', 2025, 'consolidated', 'Công ty TNHH Kiểm toán VACO', 'qualified', 0, NULL),
('VIH_2018_consolidated', 'VIH', 2018, 'consolidated', 'Công ty TNHH Kiểm toán AASC', 'unqualified', 1, 'Báo cáo tài chính đang phản ánh tổng số nợ ngắn hạn lớn hơn tài sản ngắn hạn là 90,76 tỷ VND. Tuy nhiên, Công ty vẫn trình bày trên cơ sở giả định hoạt động liên tục do được sự hỗ trợ tài chính từ Tổng Công ty Viglacera - CTCP (công ty mẹ), dây chuyền sản xuất gạch bán sứ đã hoạt động ổn định, sản phẩm tiêu thụ tăng cao, và Công ty dự kiến đảm bảo cân đối đủ vốn lưu động.'),
('VIE_2023_consolidated', 'VIE', 2023, 'consolidated', 'Công ty TNHH Kiểm toán VACO', 'qualified', 0, NULL),
