('VIG_2024_consolidated', 'VIG', 2024, 'consolidated', 'Công ty TNHH Kiểm toán và Tư vấn UHY', 'unqualified', 0, NULL),
('VIG_2023_consolidated', 'VIG', 2023, 'consolidated', 'Công ty TNHH Kiểm toán và Tư vấn UHY', 'unqualified', 0, NULL),
('VIM_2021_consolidated', 'VIM', 2021, 'consolidated', 'Công ty TNHH Hãng Kiểm toán AASC', 'unqualified', 0, NULL),
('VIG_2021_consolidated', 'VIG', 2021, 'consolidated', 'Chi nhánh Công ty TNHH Kiểm toán - Tư vấn Đất Việt tại Hà Nội', 'unqualified', 1, 'Lỗ lũy kế âm 167,28 tỷ đồng, hoạt động cầm chừng. Công ty TNHH MTV Đầu tư và Phát triển Nông nghiệp Hà Nội (Handico) yêu cầu thanh toán toàn bộ nợ gốc và lãi, đe dọa thủ tục phá sản nếu không thanh toán. Công ty chưa có phương án hay nguồn tiền để trả nợ.'),
('VIG_2022_consolidated', 'VIG', 2022, 'consolidated', 'Công ty TNHH Kiểm toán và Tư vấn UHY', 'unqualified', 0, NULL),
('VIG_2019_consolidated', 'VIG', 2019, 'consolidated', 'Công ty TNHH Hãng Kiểm toán AASC', 'unqualified', 1, 'Lỗ lũy kế âm 165,2 tỷ đồng, hoạt động cầm chung, có nghi ngờ đáng kể về khả năng hoạt động liên tục.'),
('VIG_2017_consolidated', 'VIG', 2017, 'consolidated', 'Công ty TNHH Hãng Kiểm toán AASC', 'unqualified', 1, 'Tại thời điểm 31/12/2017, lỗ lũy kế trên báo cáo tình hình tài chính của Công ty là âm 142,89 tỷ đồng, hoạt động của Công ty duy trì ở mức độ cầm chừng. Sự kiện này cho thấy có yếu tố không chắc chắn trọng yếu có thể dẫn đến nghi ngờ đáng kể về khả năng hoạt động liên tục của Công ty. Tuy nhiên, báo cáo tài chính vẫn được lập trên cơ sở giả định hoạt động liên tục do năm 2017 Công ty hoạt động có lãi và lưu chuyển tiền thuần từ hoạt động kinh doanh dương.'),
('VIG_2018_consolidated', 'VIG', 2018, 'consolidated', 'Công ty TNHH Hãng Kiểm toán AASC', 'unqualified', 1, 'Tại thời điểm 31/12/2018, lỗ lũy kế trên báo cáo tình hình tài chính của Công ty là âm 141,26 tỷ đồng. Hoạt động của Công ty duy trì ở mức độ cầm chừng. Sự kiện này cho thấy có yếu tố không chắc chắn trọng yếu có thể dẫn đến nghi ngờ đáng kể về khả năng hoạt động liên tục. Tuy nhiên, hoạt động kinh doanh trong năm có lãi, lưu chuyển tiền thuần từ hoạt động kinh doanh dương, và Công ty có kế hoạch mở rộng cơ sở kinh doanh, phát triển thêm khách hàng trong năm tới. Báo cáo tài chính vẫn được lập trên cơ sở giả định về hoạt động liên tục.'),
('VIG_2015_consolidated', 'VIG', 2015, 'consolidated', 'Công ty TNHH Hãng Kiểm toán AASC', 'unqualified', 0, NULL),
('VIG_2016_consolidated', 'VIG', 2016, 'consolidated', 'Hãng Kiểm toán AASC', 'unqualified', 0, NULL);
INSERT OR REPLACE INTO `audit_reports` (`id`, `ticker`, `year`, `report_type`, `auditor_name`, `audit_opinion`, `going_concern_issue`, `going_concern_detail`) VALUES
('VIF_2025_parent', 'VIF', 2025, 'parent', 'Công ty TNHH Ernst & Young Việt Nam', 'unqualified', 0, NULL),
('VIF_2021_consolidated', 'VIF', 2021, 'consolidated', 'Công ty Trách nhiệm Hữu hạn Ernst & Young Việt Nam', 'unqualified', 0, NULL),
('VIG_2020_consolidated', 'VIG', 2020, 'consolidated', 'Công ty TNHH Kiểm toán - Tư vấn Đất Việt', 'unqualified', 1, 'Lỗ lũy kế âm 168,71 tỷ đồng; lưu chuyển tiền thuần từ hoạt động kinh doanh âm 0,6 tỷ đồng; hoạt động Công ty duy trì ở mức cầm chưng. Kiểm toán viên cho thấy có yếu tố không chắc chắn trọng yếu có thể dẫn đến nghi ngờ đáng kể về khả năng hoạt động liên tục của Công ty. Báo cáo tài chính vẫn được lập trên cơ sở giả định về hoạt động liên tục.'),
('VIF_2021_parent', 'VIF', 2021, 'parent', 'Công ty Trách nhiệm Hữu hạn Ernst & Young Việt Nam', 'unqualified', 0, NULL),
